#include <stdio.h>
#include <unistd.h>
#include <sys/wait.h>

int main() {
    int pipefd[2];
    pid_t pid;
    char write_msg[] = "Hello from Parent!";
    char read_msg[100];

    // Create pipe
    pipe(pipefd);

    pid = fork();

    if (pid == 0) {
        // Child process - reads from pipe
        close(pipefd[1]); // Close write end
        read(pipefd[0], read_msg, sizeof(read_msg));
        printf("Child received: %s\n", read_msg);
        close(pipefd[0]);
    } else {
        // Parent process - writes to pipe
        close(pipefd[0]); // Close read end
        write(pipefd[1], write_msg, sizeof(write_msg));
        printf("Parent sent message\n");
        close(pipefd[1]);
        wait(NULL); // Wait for child
    }
    return 0;
}

// Writer Process (process1.c)
#include <stdio.h>
#include <sys/shm.h>
#include <sys/ipc.h>

int main() {
    key_t key = ftok("/tmp", 'R');
    int shmid = shmget(key, 1024, IPC_CREAT | 0666);
    char *str = (char*)shmat(shmid, NULL, 0);

    printf("Writing to shared memory: ");
    fgets(str, 1024, stdin);

    printf("Written: %s", str);
    shmdt(str);
    return 0;
}

// Reader Process (process2.c)
#include <stdio.h>
#include <sys/shm.h>
#include <sys/ipc.h>

int main() {
    key_t key = ftok("/tmp", 'R');
    int shmid = shmget(key, 1024, 0666);
    char *str = (char*)shmat(shmid, NULL, SHM_RDONLY);

    printf("Reading from shared memory: %s", str);
    shmdt(str);

    // Cleanup
    shmctl(shmid, IPC_RMID, NULL);
    return 0;
}

import java.io.*;

public class MessageQueueDemo {
    public static void main(String[] args) throws IOException {
        PipedInputStream in = new PipedInputStream();
        PipedOutputStream out = new PipedOutputStream(in);

        // Producer Thread
        Thread producer = new Thread(() -> {
            try {
                String[] messages = {"Message 1", "Message 2", "Message 3"};
                for (String msg : messages) {
                    out.write(msg.getBytes());
                    out.write('\n'); // Message delimiter
                    System.out.println("Sent: " + msg);
                    Thread.sleep(500);
                }
                out.close();
            } catch (Exception e) { e.printStackTrace(); }
        });

        // Consumer Thread
        Thread consumer = new Thread(() -> {
            try {
                int data;
                StringBuilder msg = new StringBuilder();
                while ((data = in.read()) != -1) {
                    char c = (char) data;
                    if (c == '\n') {
                        System.out.println("Received: " + msg.toString());
                        msg.setLength(0);
                    } else {
                        msg.append(c);
                    }
                }
                in.close();
            } catch (Exception e) { e.printStackTrace(); }
        });

        producer.start();
        consumer.start();

        try {
            producer.join();
            consumer.join();
        } catch (InterruptedException e) {}
    }
}
